import{_ as n,C as a,o as d,c as h,E as e,a3 as s}from"./chunks/framework.CjmLrUhD.js";const k=JSON.parse('{"title":"电商运营部门知识库","description":"用于新人了解部门角色、业务资料、任务机制和常用协作入口。","frontmatter":{"title":"电商运营部门知识库","description":"用于新人了解部门角色、业务资料、任务机制和常用协作入口。"},"headers":[],"relativePath":"team/department-kb.md","filePath":"team/department-kb.md","lastUpdated":1783072050000}'),c={name:"team/department-kb.md"};function p(u,t,m,_,b,q){const r=a("DocHero"),l=a("ModuleFlow"),o=a("RelatedDocs"),i=a("ImageGallery");return d(),h("div",null,[e(r,{"module-id":"department-kb","image-count":0,"section-count":15}),e(l,{"module-id":"department-kb"}),e(o,{"module-id":"department-kb"}),t[0]||(t[0]=s('<h1 id="电商运营部门知识库执行手册" tabindex="-1">电商运营部门知识库执行手册 <a class="header-anchor" href="#电商运营部门知识库执行手册" aria-label="Permalink to &quot;电商运营部门知识库执行手册&quot;">​</a></h1><h2 id="模块定位" tabindex="-1">模块定位 <a class="header-anchor" href="#模块定位" aria-label="Permalink to &quot;模块定位&quot;">​</a></h2><p>这篇文档面向新入职运营和带教负责人。它的作用不是简单欢迎新人，而是让新人快速理解运营部门在公司里的角色、每天要交付什么、需要阅读哪些资料，以及遇到请假、报销、协作时去哪里处理。</p><h2 id="一、部门介绍" tabindex="-1">一、部门介绍 <a class="header-anchor" href="#一、部门介绍" aria-label="Permalink to &quot;一、部门介绍&quot;">​</a></h2><p>运营部门的核心职责是把公司战略目标落到店铺、产品、活动和日常动作上。运营需要围绕月目标、月计划和周计划，调动客服、设计、仓库等岗位配合，把产品销售结果持续做出来。</p><h3 id="_1-了解业务" tabindex="-1">1. 了解业务 <a class="header-anchor" href="#_1-了解业务" aria-label="Permalink to &quot;1. 了解业务&quot;">​</a></h3><p>新人第一天要先理解部门为什么重要。运营不是只看后台数据，也不是只上链接。运营要对销售额、付费投放、产品表现、客服反馈、设计素材和库存节奏保持敏感。</p><p>日常工作可以拆成九类：产品上新、上新测款测图、每日数据跟踪、新品推爆、老品优化、爆款维护、活动策划、周会复盘、月会规划。新人不需要第一天全部独立完成，但必须知道每类工作最终服务于销售结果。</p><h3 id="_2-日常工作节奏" tabindex="-1">2. 日常工作节奏 <a class="header-anchor" href="#_2-日常工作节奏" aria-label="Permalink to &quot;2. 日常工作节奏&quot;">​</a></h3><p>每天上班的第一件事是写当天工作计划，并发到公司群或部门指定位置。入职第一周可由带教负责人协助完成，不要求新人独立制定完整计划。</p><p>日常时间按公司制度执行。请假通过飞书发起，部门负责人审核后同步人事。涉及样品、打车、软件、付费工具或合作费用，需要按报销流程提前申请或补充凭证。</p><h3 id="_3-组织架构" tabindex="-1">3. 组织架构 <a class="header-anchor" href="#_3-组织架构" aria-label="Permalink to &quot;3. 组织架构&quot;">​</a></h3><p>新人要在入职第一周弄清楚自己和关键协作岗位的关系：直属负责人是谁，美工对接谁，客服对接谁，仓库对接谁，活动或投放问题找谁。组织架构不是挂图，而是解决问题时的路径。</p><h2 id="二、必读资料" tabindex="-1">二、必读资料 <a class="header-anchor" href="#二、必读资料" aria-label="Permalink to &quot;二、必读资料&quot;">​</a></h2><p>资料阅读要和任务绑定。新人读完资料后，应能回答“这份资料用于什么场景”“我什么时候会用到”“我需要输出什么结果”。</p><h3 id="_1-业务规划资料" tabindex="-1">1. 业务规划资料 <a class="header-anchor" href="#_1-业务规划资料" aria-label="Permalink to &quot;1. 业务规划资料&quot;">​</a></h3><p>业务规划资料帮助新人理解公司当前重点类目、重点产品、销售目标和资源投入方向。读完后要能说清楚本月重点产品、店铺目标和运营节奏。</p><p><strong>附件：9.追美工+客服拿结果OGSM+PDCA.xlsx</strong></p><h3 id="_2-单品运营流程" tabindex="-1">2. 单品运营流程 <a class="header-anchor" href="#_2-单品运营流程" aria-label="Permalink to &quot;2. 单品运营流程&quot;">​</a></h3><p>单品运营流程是新人最先要掌握的主线。一个链接从上新到测款、测图、优化、放量、维护，每一步都有对应动作和数据判断。新人应优先学习测款 SOP、测图 SOP、新品打爆 SOP。</p><h3 id="_3-跟美工和客服沟通追结果" tabindex="-1">3. 跟美工和客服沟通追结果 <a class="header-anchor" href="#_3-跟美工和客服沟通追结果" aria-label="Permalink to &quot;3. 跟美工和客服沟通追结果&quot;">​</a></h3><p>运营的很多结果不是自己一个人完成的。跟美工沟通时要给清楚目标、参考、尺寸、卖点和交付时间；跟客服沟通时要关注咨询问题、转化障碍、差评风险和买家反馈。</p><h3 id="_4-经验分享" tabindex="-1">4. 经验分享 <a class="header-anchor" href="#_4-经验分享" aria-label="Permalink to &quot;4. 经验分享&quot;">​</a></h3><p>经验分享资料用于补充案例。新人读经验时不要只记结论，要还原当时的产品、流量、预算、团队和时间条件。不同条件下，经验不能直接照搬。</p><h2 id="三、新人任务" tabindex="-1">三、新人任务 <a class="header-anchor" href="#三、新人任务" aria-label="Permalink to &quot;三、新人任务&quot;">​</a></h2><p>新人任务建议分三阶段。第一阶段是熟悉业务和工具，完成资料阅读、后台入口认识和基础数据查看。第二阶段是跟做任务，参与测款、测图、竞品分析或周报整理。第三阶段是独立输出，完成一个小模块的执行和复盘。</p><p>每个任务都要有交付物。例如读资料要输出阅读笔记；看竞品要输出竞品拆解表；跟测款要输出数据记录；参加周会要输出行动项。</p><p><a href="https://slx7pq9fbb.feishu.cn/wiki/wikcnYa2TF7lnLB8I9ycdKIBNkf" target="_blank" rel="noreferrer">新人任务看板</a></p><h2 id="四、常用群组和协作入口" tabindex="-1">四、常用群组和协作入口 <a class="header-anchor" href="#四、常用群组和协作入口" aria-label="Permalink to &quot;四、常用群组和协作入口&quot;">​</a></h2><p>公司大群用于公司级通知和通用信息，部门群用于运营任务同步和日常协作。新人加入群后先观察信息规则，不要把所有问题都丢到大群。能查资料的先查资料，需要决策的找负责人，需要跨部门配合的按流程同步。</p><h2 id="带教负责人检查清单" tabindex="-1">带教负责人检查清单 <a class="header-anchor" href="#带教负责人检查清单" aria-label="Permalink to &quot;带教负责人检查清单&quot;">​</a></h2><ul><li>新人是否知道部门核心目标</li><li>新人是否理解每天要写工作计划</li><li>新人是否知道请假和报销路径</li><li>新人是否完成必读资料和任务看板</li><li>新人是否能说清楚测款、测图、新品打爆的基本流程</li><li>新人是否知道遇到设计、客服、仓库问题找谁</li></ul><h2 id="新人首周交付物" tabindex="-1">新人首周交付物 <a class="header-anchor" href="#新人首周交付物" aria-label="Permalink to &quot;新人首周交付物&quot;">​</a></h2><ul><li>业务理解笔记</li><li>运营部门日常工作清单</li><li>一份竞品或产品分析小作业</li><li>一份测款/测图 SOP 阅读总结</li><li>当前负责事项的每日计划和复盘</li></ul>',34)),e(i,{"module-id":"department-kb"})])}const P=n(c,[["render",p]]);export{k as __pageData,P as default};
